/*
 * Amdahl's Law Calculator - C Implementation
 * ===========================================
 * Calculates theoretical speedup and efficiency for parallel programs.
 *
 * Formula: Speedup = 1 / [(1 - P) + (P / N)]
 * 
 * Compile: gcc -o amdahl amdahl.c -lm
 */

#include <stdio.h>
#include <stdlib.h>
#include <math.h>

/* Structure to hold analysis results */
typedef struct {
 int num_processors;
 double speedup;
 double efficiency;
 double percent_of_max;
} AnalysisResult;

/* Calculate speedup using Amdahl's Law */
double calculate_speedup(double parallel_fraction, int num_processors) {
 if (parallel_fraction < 0.0 || parallel_fraction > 1.0) {
 fprintf(stderr, "Error: Parallel fraction must be between 0 and 1\n")
 return -1.0;
 }
 if (num_processors <= 0) {
 fprintf(stderr, "Error: Number of processors must be positive\n");
 return -1.0;
 }

 double sequential_fraction = 1.0 - parallel_fraction;
 double parallel_contribution = parallel_fraction / num_processors;

 /* Amdahl's Law: Speedup = 1 / [S + P/N] */
 double speedup = 1.0 / (sequential_fraction + parallel_contribution);

 return speedup;
}

/* Calculate maximum speedup as N approaches infinity */
double calculate_max_speedup(double parallel_fraction) {
 double sequential_fraction = 1.0 - parallel_fraction;

 if (sequential_fraction <= 0.0) {
 return INFINITY; /* Fully parallelizable */
 }

 return 1.0 / sequential_fraction;
}

/* Calculate parallel efficiency */
double calculate_efficiency(double parallel_fraction, int num_processors) {
 double speedup = calculate_speedup(parallel_fraction, num_processors);
 return speedup / num_processors;
}

/* Calculate minimum processors needed for target speedup */
int processors_needed(double parallel_fraction, double target_speedup) {
 double sequential_fraction = 1.0 - parallel_fraction;
 double max_speedup = calculate_max_speedup(parallel_fraction);

 if (target_speedup > max_speedup) {
 fprintf(stderr, "Error: Target speedup %.2fx exceeds maximum %.2fx\n",
 target_speedup, max_speedup);
 return -1;
 }

 /* Derived: N = P / ((1/S) - S) where S is target speedup */
 double denominator = (1.0 / target_speedup) - sequential_fraction;
 double n = parallel_fraction / denominator;

 return (int)ceil(n);
}

/* Gustafson's Law: Scaled speedup */
double gustafson_speedup(double sequential_fraction, int num_processors) {
 return num_processors + (1.0 - num_processors) * sequential_fraction;
}

/* Analyze scaling for a range of processor counts */
AnalysisResult* analyze_scaling(double parallel_fraction, int max_processors, int *result_count) {
 *result_count = max_processors;
 AnalysisResult *results = (AnalysisResult*)malloc(max_processors * sizeof(AnalysisResult));

 if (!results) {
 fprintf(stderr, "Memory allocation failed\n");
 return NULL;
 }

 double max_speedup = calculate_max_speedup(parallel_fraction);

 for (int i = 0; i < max_processors; i++) {
 int n = i + 1; /* Processors from 1 to max_processors */
 results[i].num_processors = n;
 results[i].speedup = calculate_speedup(parallel_fraction, n);
 results[i].efficiency = results[i].speedup / n;
 results[i].percent_of_max = (results[i].speedup / max_speedup) * 100.0;
 }

 return results;
}

/* Print formatted speedup table */
void print_speedup_table(double parallel_fraction, int max_processors) {
 printf("\n=============================================================\n");
 printf("Amdahl's Law Analysis\n");
 printf("=============================================================\n");
 printf("Parallel Fraction (P): %.0f%%\n", parallel_fraction * 100);
 printf("Sequential Fraction: %.0f%%\n", (1 - parallel_fraction) * 100);
 printf("Maximum Speedup: %.2fx\n", calculate_max_speedup(parallel_fraction));
 printf("=============================================================\n\n");

 printf("%-12s %-12s %-12s %-12s\n", 
 "Processors", "Speedup", "Efficiency", "% of Max");
 printf("---------------------------------------------------------\n");

 /* Print selected processor counts */
 int selected[] = {1, 2, 4, 8, 16, 32, 64, 128, 256, 512, 1024};
 int num_selected = sizeof(selected) / sizeof(selected[0]);

 for (int i = 0; i < num_selected; i++) {
 int n = selected[i];
 if (n > max_processors) break;

 double speedup = calculate_speedup(parallel_fraction, n);
 double efficiency = calculate_efficiency(parallel_fraction, n);
 double max_speedup = calculate_max_speedup(parallel_fraction);
 double pct_of_max = (speedup / max_speedup) * 100.0;

 printf("%-12d %-12.2f %-11.1f%% %-11.1f%%\n",
 n, speedup, efficiency * 100, pct_of_max);
 }
}

/* Analyze GPU program with overheads */
void analyze_gpu_program(void) {
 printf("\n=============================================================\n");
 printf("GPU Program Analysis (with overheads)\n");
 printf("=============================================================\n");

 /* Typical GPU program breakdown */
 double data_transfer_overhead = 0.05; /* 5% CPU-GPU transfer */
 double kernel_launch_overhead = 0.02; /* 2% kernel setup */
 double sequential_total = data_transfer_overhead + kernel_launch_overhead;
 double parallel_fraction = 1.0 - sequential_total;

 printf("Program Components:\n");
 printf(" - Data transfer (CPU->GPU): %.0f%%\n", data_transfer_overhead * 100);
 printf(" - Kernel launch overhead: %.0f%%\n", kernel_launch_overhead * 100);
 printf(" - Parallel computation: %.0f%%\n", parallel_fraction * 100);
 printf("\n");

 printf("%-12s %-12s %-12s\n", "GPU Cores", "Speedup", "Efficiency");
 printf("--------------------------------------------\n");

 int gpu_counts[] = {16, 64, 256, 512, 1024, 2048, 4096};
 int num_counts = sizeof(gpu_counts) / sizeof(gpu_counts[0]);

 for (int i = 0; i < num_counts; i++) {
 int n = gpu_counts[i];
 double speedup = calculate_speedup(parallel_fraction, n);
 double efficiency = calculate_efficiency(parallel_fraction, n);

 printf("%-12d %-12.2f %-11.1f%%\n", n, speedup, efficiency * 100);
 }

 printf("\nMaximum theoretical speedup: %.2fx\n", 
 calculate_max_speedup(parallel_fraction));
 printf("Note: Data transfer overhead significantly limits speedup!\n");
}

/* Compare Amdahl and Gustafson */
void compare_laws(double parallel_fraction) {
 double sequential_fraction = 1.0 - parallel_fraction;

 printf("\n=============================================================\n");
 printf("Amdahl's Law vs Gustafson's Law Comparison\n");
 printf("=============================================================\n");
 printf("P = %.0f%% parallel, S = %.0f%% sequential\n\n",
 parallel_fraction * 100, sequential_fraction * 100);

 printf("%-12s %-12s %-12s %-12s\n", 
 "Processors", "Amdahl", "Gustafson", "Ideal");
 printf("---------------------------------------------------------\n");

 int processors[] = {10, 50, 100, 500, 1000};
 int num_proc = sizeof(processors) / sizeof(processors[0]);

 for (int i = 0; i < num_proc; i++) {
 int n = processors[i];
 double amdahl = calculate_speedup(parallel_fraction, n);
 double gustafson = gustafson_speedup(sequential_fraction, n);

 printf("%-12d %-12.2f %-12.2f %-12.2f\n",
 n, amdahl, gustafson, (double)n);
 }

 printf("\nInterpretation:\n");
 printf("- Amdahl: Fixed problem size, speedup limited by sequential portion\n");
 printf("- Gustafson: Problem scales with processors, more optimistic\n");
}

/* Calculate diminishing returns */
void analyze_diminishing_returns(double parallel_fraction) {
 double max_speedup = calculate_max_speedup(parallel_fraction);

 printf("\n=============================================================\n");
 printf("Diminishing Returns Analysis\n");
 printf("=============================================================\n");
 printf("Maximum possible speedup: %.2fx\n\n", max_speedup);

 printf("Processors needed to achieve percentage of maximum:\n");
 printf("%-12s %-12s %-12s %-12s\n",
 "% of Max", "Target Speedup", "Processors", "Efficiency");
 printf("---------------------------------------------------------\n");

 double percentages[] = {0.50, 0.75, 0.90, 0.95, 0.99};
 int num_pct = sizeof(percentages) / sizeof(percentages[0]);

 for (int i = 0; i < num_pct; i++) {
 double target_pct = percentages[i];
 double target_speedup = target_pct * max_speedup;
 int n = processors_needed(parallel_fraction, target_speedup);

 if (n > 0) {
 double eff = calculate_efficiency(parallel_fraction, n);
 printf("%-12.0f %-12.2f %-12d %-11.1f%%\n",
 target_pct * 100, target_speedup, n, eff * 100);
 }
 }

 printf("\nKey Insight: Small sequential fractions still limit speedup!\n");
 printf("Even with 99%% parallelizable code, you need many processors\n");
 printf("to get close to the theoretical maximum.\n");
}

int main(int argc, char *argv[]) {
 /* Example 1: Basic Amdahl's Law calculation */
 printf("=============================================================\n");
 printf("EXAMPLE 1: Basic Amdahl's Law Calculation\n");
 printf("=============================================================\n");

 double P = 0.80; /* 80% parallelizable */
 int N = 4;

 double speedup = calculate_speedup(P, N);
 double efficiency = calculate_efficiency(P, N);
 double max_speedup = calculate_max_speedup(P);

 printf("Given: P = %.0f%% parallelizable, N = %d processors\n", P * 100, N);
 printf("Speedup = 1 / [(1-P) + (P/N)]\n");
 printf(" = 1 / [%.2f + (%.2f/%d)]\n", 1-P, P, N);
 printf(" = 1 / %.4f\n", (1-P) + (P/N));
 printf(" = %.2fx\n\n", speedup);

 printf("Results:\n");
 printf(" Sequential portion: %.0f%%\n", (1-P) * 100);
 printf(" Speedup achieved: %.2fx\n", speedup);
 printf(" Parallel efficiency: %.1f%%\n", efficiency * 100);
 printf(" Maximum speedup: %.2fx (with infinite processors)\n", max_speedup);

 /* Example 2: Speedup table */
 printf("\n");
 print_speedup_table(0.90, 256);

 /* Example 3: GPU analysis */
 analyze_gpu_program();

 /* Example 4: Compare laws */
 compare_laws(0.90);

 /* Example 5: Diminishing returns */
 analyze_diminishing_returns(0.95);

 /* Cleanup */
 int count;
 AnalysisResult *results = analyze_scaling(0.80, 100, &count);
 if (results) {
 free(results);
 }

 return 0;
}
